class MockUserRepository extends Mock implements UserRepository {}

void main() {
  late GetUserProfile useCase;
  late MockUserRepository repository;

  setUp(() {
    repository = MockUserRepository();
    useCase = GetUserProfile(repository);
  });

  test('should return user when repository finds user', () async {
    final user = User(id: '1', name: 'John');
    when(() => repository.getUserById('1')).thenAnswer((_) async => Right(user));

    final result = await useCase('1');

    expect(result, Right(user));
    verify(() => repository.getUserById('1')).called(1);
  });
}

blocTest<CartBloc, CartState>(
  'emits [CartLoading, CartLoaded] when AddToCart succeeds',
  build: () {
    when(() => repository.addItem(any())).thenAnswer((_) async => Cart(items: [product]));
    return CartBloc(repository);
  },
  act: (bloc) => bloc.add(AddToCart(product)),
  expect: () => [
    CartLoading(),
    CartLoaded(Cart(items: [product])),
  ],
  verify: (_) {
    verify(() => repository.addItem(product)).called(1);
  },
);

testWidgets('ProductCard shows product name and price', (tester) async {
