// Fake - full implementation for testing
class FakeUserRepository extends Fake implements UserRepository {
  final List<User> _users = [];

  @override
  Future<Either<Failure, User>> getUserById(String id) async {
    final user = _users.firstWhereOrNull((u) => u.id == id);
    return user != null ? Right(user) : Left(NotFoundFailure('User not found'));
  }

  void addUser(User user) => _users.add(user);
}

// Use Fake when you need realistic behavior
// Use Mock when you need to verify interactions

class TestFixtures {
  static User user({
    String id = '1',
    String name = 'Test User',
    String email = 'test@example.com',
  }) => User(id: id, name: name, email: email);

  static Product product({
    String id = '1',
    String name = 'Test Product',
    double price = 29.99,
  }) => Product(id: id, name: name, price: price);

  static Order order({List<Product>? items}) => Order(
    id: '1',
    items: items ?? [product()],
    total: items?.fold(0.0, (sum, p) => sum + p.price) ?? 29.99,
  );
}

testWidgets('product card is accessible', (tester) async {
  final handle = tester.ensureSemantics();
  await tester.pumpWidget(MaterialApp(home: ProductCard(product: testProduct)));

  // Check semantic labels
  expect(
    tester.getSemantics(find.byType(ProductCard)),
    matchesSemantics(label: 'Laptop, \$999.99, Add to cart'),
  );

  // Verify tap target size (48x48 minimum)
  final size = tester.getSize(find.byType(ElevatedButton));
  expect(size.width, greaterThanOrEqualTo(48));
  expect(size.height, greaterThanOrEqualTo(48));

  handle.dispose();
});

testWidgets('scrolling performance', (tester) async {
  await tester.pumpWidget(const MyApp());
  await tester.pumpAndSettle();

  final listFinder = find.byType(ListView);

  // Measure scroll performance
  final timeline = await tester.traceAction(() async {
    await tester.fling(listFinder, const Offset(0, -500), 10000);
    await tester.pumpAndSettle();
  });

  // Check no frames took longer than 16ms
  // (In integration test, check timeline for jank)
});

